def classify_score(score: int) -> str:
    if score >= 80:
        return "accept"
    elif score >= 50:
        return "review"
    else:
        return "reject"

cases = [
    (90, "accept"),
    (55, "review"),
    (10, "reject"),
    (80, "accept"),
    (50, "review"),
]
