def rango_edad(e):
    if e is None:
        return "review"
    if 18 <= e <= 65:
        return "accept"
    if e < 0 or e > 120:
        return "reject"
    return "review"

cases = [(18, "accept"), (17, "review"), (None, "review"), (30, "accept")]
for val, expected in cases:
    got = rango_edad(val)
    assert got == expected
    print("PASS", val, got)
